import sys
class Solution:
    def recoverMaxHeapAfterDeletion(self, arr: list[int]) -> None:
        if len(arr) == 1:
            return
        arr.pop(0)
        n = len(arr)
        for i in range(n - 1, -1, -1):
            self.heapify(arr, i, n)

    def heapify(self, arr: list[int], i: int, n: int) -> None:
        largest = i
        left = 2 * i + 1
        right = 2 * i + 2

        if left < n and arr[left] > arr[largest]:
            largest = left
        if right < n and arr[right] > arr[largest]:
            largest = right

        if largest != i:
            swap(arr[i], arr[largest])
            self.heapify(arr, largest, n)

def swap(arr: list[int], i: int, j: int) -> None:
    arr[i], arr[j] = arr[j], arr[i]

