#include <iostream>
#include <vector>
using namespace std;

void recoverMaxHeapAfterDeletion(vector<int>& arr) {
    if (arr.size() == 1) {
        return;
    }
    arr.erase(arr.begin());
    for (int i = arr.size() - 1; i >= 0; i--) {
        heapify(arr, i);
    }
}

void heapify(vector<int>& arr, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < arr.size() && arr[left] > arr[largest]) {
        largest = left;
    }
    if (right < arr.size() && arr[right] > arr[largest]) {
        largest = right;
    }

    if (largest != i) {
        swap(arr[i], arr[largest]);
        heapify(arr, largest);
    }
}

void swap(vector<int>& arr, int i, int j) {
    arr[i] = arr[j];
    arr[j] = arr[i];
}

int main() {
    int n;
    cin >> n;
    cin.ignore();
    vector<int> arr(n);
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    recoverMaxHeapAfterDeletion(arr);
    for (int i = 0; i < arr.size(); i++) {
        cout << arr[i] << ' ';\
    }
    cout << '\n';
    return 0;
}
